interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notification, setNotification] = useState<NotificationProps | null>(null);

  useEffect(() => {
    if (notificationElem) {
      const handleNotification = async (props: NotificationProps) => {
        try {
          await notificationElem.open({
            heading: props.heading,
            subheading: props.subheading,
            type: props.type,
          });
        } catch (error) {
          console.error(error);
        }
      };
      return handleNotification;
    }
  }, [notificationElem]);

  const triggerNotification = (props: NotificationProps) => {
    setNotification(props);
  };

  return { triggerNotification };
};

export default useNotification;
